{
  title: 'Angular Wrapper/FfButton',
  component: FfButton,
  tags: ['autodocs'],
  decorators: [
    moduleMetadata({
      imports: [CommonModule, FfButton]
    })
  ],
  args: {
    label: 'Launch selected brand',
    disabled: false,
    fullWidth: false,
    type: 'button'
  },
  argTypes: {
    label: { control: 'text' },
    disabled: { control: 'boolean' },
    fullWidth: { control: 'boolean' },
    type: {
      control: 'inline-radio',
      options: ['button', 'submit', 'reset']
    }
  },
  parameters: {
    docs: {
      description: {
        component:
          'Angular-generated standalone wrapper around the shared Stencil button. Brand and theme now live entirely on the outer shell and the imported CSS pack.'
      }
    }
  },
  render: (storyProperties: ButtonStoryProperties, storyContext) => {
    const brandKey = String(storyContext.globals['brand'] ?? 'brand-1');
    const themeKey = String(storyContext.globals['theme'] ?? 'light');
    const storyState = {
      label: storyProperties.label ?? 'Launch selected brand',
      disabled: storyProperties.disabled ?? false,
      fullWidth: storyProperties.fullWidth ?? false,
      type: storyProperties.type ?? 'button',
      brand: brandKey,
      theme: themeKey,
      launchCount: 0,
      launchMessage: `Ready to launch ${brandLabel(brandKey)} in ${titleFromKey(themeKey)} mode.`,
      handleLaunch() {
        storyState.launchCount += 1;
        storyState.launchMessage = `${brandLabel(brandKey)} launched in ${titleFromKey(themeKey)} mode at ${new Date().toLocaleTimeString()}.`;
      }
    };

    return {
      props: storyState,
      template: `
        <div
          [attr.data-brand]="brand"
          [attr.data-theme]="theme"
          style="display:grid;gap:1rem;max-width:420px;min-height:100vh;padding:2rem;background:var(--ff-color-canvas);color:var(--ff-color-text-primary);font-family:Inter,Arial,sans-serif"
        >
          <ff-button
            [disabled]="disabled"
            [fullWidth]="fullWidth"
            [type]="type"
            (click)="handleLaunch()"
          >
            {{ label }}
          </ff-button>

          <div
            style="display:grid;gap:0.5rem;padding:1rem;border:1px solid var(--ff-color-border-subtle);background:var(--ff-color-surface)"
          >
            <p style="margin:0;text-transform:uppercase;letter-spacing:0.12em;font-size:0.72rem;color:var(--ff-color-text-muted)">
              Launch status
            </p>
            <strong>{{ launchMessage }}</strong>
            <span style="color:var(--ff-color-text-secondary)">Launches in this session: {{ launchCount }}</span>
          </div>
        </div>
      `
    };
  }
} satisfies Meta<FfButton>

{
  title: 'Angular Wrapper/FfDropdown',
  component: FfDropdown,
  tags: ['autodocs'],
  decorators: [
    moduleMetadata({
      imports: [CommonModule, FfDropdown]
    })
  ],
  args: {
    disabled: false,
    fullWidth: true,
    label: 'Release target',
    placeholder: 'Choose a release target',
    value: 'pilot-release'
  },
  argTypes: {
    label: { control: 'text' },
    placeholder: { control: 'text' },
    disabled: { control: 'boolean' },
    fullWidth: { control: 'boolean' },
    value: {
      control: 'select',
      options: dropdownOptions.map((option) => option.value)
    }
  },
  parameters: {
    docs: {
      description: {
        component:
          'Angular standalone wrapper around the shared dropdown primitive. Selection logic remains inside Stencil while Angular only binds props and events.'
      }
    }
  },
  render: (storyProperties: DropdownStoryProperties, storyContext) => {
    const brandKey = String(storyContext.globals['brand'] ?? 'brand-1');
    const themeKey = String(storyContext.globals['theme'] ?? 'light');
    const selectedValue = storyProperties.value ?? 'pilot-release';
    const selectedLabel = labelFromValue(selectedValue);

    const storyState = {
      brand: brandKey,
      disabled: storyProperties.disabled ?? false,
      fullWidth: storyProperties.fullWidth ?? true,
      label: storyProperties.label ?? 'Release target',
      options: dropdownOptions,
      placeholder: storyProperties.placeholder ?? 'Choose a release target',
      selectedLabel,
      selectedValue,
      theme: themeKey,
      handleValueChange(customEvent: CustomEvent<{ label: string; value: string }>) {
        storyState.selectedLabel = customEvent.detail.label;
        storyState.selectedValue = customEvent.detail.value;
      }
    };

    return {
      props: storyState,
      template: `
        <div
          [attr.data-brand]="brand"
          [attr.data-theme]="theme"
          style="display:grid;gap:1rem;max-width:28rem;min-height:100vh;padding:2rem;background:var(--ff-color-canvas);color:var(--ff-color-text-primary);font-family:Inter,Arial,sans-serif"
        >
          <ff-dropdown
            [disabled]="disabled"
            [fullWidth]="fullWidth"
            [label]="label"
            [options]="options"
            [placeholder]="placeholder"
            [value]="selectedValue"
            (ffValueChange)="handleValueChange($event)"
          ></ff-dropdown>

          <div
            role="status"
            aria-live="polite"
            style="display:grid;gap:0.5rem;padding:1rem;border:1px solid var(--ff-color-border-subtle);background:var(--ff-color-surface)"
          >
            <p style="margin:0;text-transform:uppercase;letter-spacing:0.12em;font-size:0.72rem;color:var(--ff-color-text-muted)">
              Selection status
            </p>
            <strong>Current selection: {{ selectedLabel }}</strong>
          </div>
        </div>
      `
    };
  }
} satisfies Meta<FfDropdown>

